1	#!/usr/bin/env node
2	'use strict';
3	// eval/reference-set/run-facts.js - run the FACTS LAYER over the reference set.
4	//
5	// verify.js checks an already-built engine PAYLOAD against the hand-verified set. This harness
6	// closes the loop one stage earlier: for every fixture EvidenceBundle in eval/reference-set/fixtures/
7	// it RUNS the four facts doors directly -
8	//
9	//     facts/identity.js       -> legal_name, company_number
10	//     facts/jurisdiction.js   -> bound jurisdictions (the nexus)
11	//     facts/sector.js         -> sector family + sub-sector
12	//     facts/capabilities.js   -> capability predicates (exercised; never fabricates)
13	//
14	// and compares what they produce against reference-set.json under the ONE law the whole estate lives by:
15	//
16	//     MATCH        a door asserts a value and it agrees with the verified expectation
17	//     ABSTAIN      a door omits or marks needs-review a value the set expects       (allowed, logged)
18	//     OK*          a door's expectations are met by abstention because the CAPTURED bundle is an
19	//                  explicit unreachable (bot-walled / SPA shell)                     (allowed, logged)
20	//     MISSING      no fixture on disk for a verified firm - an uncovered gap         (FAIL, exit 2)
21	//     CONTRADICT   a door asserts a value that disagrees with a verified expectation (FAIL, exit 1)
22	//
23	// Canonicalisation is via facts/vocabulary.js (the single vocabulary door): the engine's sector
24	// tree speaks in canonical family keys ('law-firms'), the reference set records human aliases
25	// ('legal'); both sides pass through canonicalSector() before they are compared, so a vocabulary
26	// alias never masquerades as a contradiction. The comparison itself delegates to verify.js's
27	// verifyPayload() so this harness and the CI payload gate judge by exactly the same rules.
28	//
29	// Usage:
30	//   node eval/reference-set/run-facts.js [--set <reference-set.json>] [--fixtures <dir>] [--domain <d>] [--json]
31	//
32	// Exit codes: 0 = no contradictions (abstentions + unreachable allowed),
33	//             1 = at least one door contradicted hand-verified ground truth,
34	//             2 = a door threw, or a runner/data error (unreadable set, no fixtures dir, ...).
35	
36	const fs = require('fs');
37	const path = require('path');
38	
39	const identity = require('../../facts/identity.js');
40	const jurisdiction = require('../../facts/jurisdiction.js');
41	const sector = require('../../facts/sector.js');
42	const capabilities = require('../../facts/capabilities.js');
43	const vocabulary = require('../../facts/vocabulary.js');
44	const { verifyPayload, loadReferenceSet, findFirm } = require('./verify.js');
45	
46	const DEFAULT_SET = path.join(__dirname, 'reference-set.json');
47	const DEFAULT_FIXTURES = path.join(__dirname, 'fixtures');
48	
49	// The canonical sector tree, loaded once through the sector door (which loads it through the
50	// vocabulary door). familyOf() climbs a sub-family to its top family key.
51	const TREE = sector.loadVocabulary().TREE;
52	
53	function canonSector(s) {
54	  if (s == null) return null;
55	  const c = vocabulary.canonicalSector(s);
56	  return c || s;
57	}
58	
59	// deriveSectorFamily(facts) -> the canonicalised sector FAMILY key the sector door emitted, or
60	// null when the door produced no sector value. Split out of factsToPayload (health-gate caps).
61	function deriveSectorFamily(facts) {
62	  const emitted = facts.sector && facts.sector.value; // { sector, sub_sector } | null
63	  let sectorFamily = null;
64	  if (emitted && emitted.sector) {
65	    sectorFamily = canonSector(sector.familyOf(TREE, emitted.sector));
66	  }
67	  return sectorFamily;
68	}
69	
70	// deriveBoundJurisdictions(facts) -> the jurisdiction door's bound list, projected to the code array.
71	function deriveBoundJurisdictions(facts) {
72	  return (facts.jurisdiction && Array.isArray(facts.jurisdiction.bound))
73	    ? facts.jurisdiction.bound.map((b) => b && b.jurisdiction).filter(Boolean)
74	    : [];
75	}
76	// factValueOrNull(fact) -> a facts-door field's value, or null when the door had no confident value.
77	function factValueOrNull(fact) {
78	  return fact && fact.value != null ? fact.value : null;
79	}
80	// deriveIdentityFields(facts) -> {legalName, companyNumber} off the identity door's output.
81	function deriveIdentityFields(facts) {
82	  const id = facts.identity || {};
83	  return { legalName: factValueOrNull(id.legal_name), companyNumber: factValueOrNull(id.company_number) };
84	}
85	
86	// -------------------------------------------------------------------------------------------------
87	// Turn the four facts outputs into the tolerant payload shape verify.js reads, applying the one
88	// piece of canonicalisation the facts layer owes the comparator: lift the engine's emitted sector
89	// node to its canonical FAMILY key. The reference set's `sector` is a family; sub-sector granularity
90	// differs between the engine's three-tier tree and the human descriptors, so sub_sector is left for
91	// the informational column (below) and never fed to the contradiction check - never contradict.
92	// -------------------------------------------------------------------------------------------------
93	function factsToPayload(domain, facts) {
94	  const sectorFamily = deriveSectorFamily(facts);
95	  const bound = deriveBoundJurisdictions(facts);
96	  const { legalName, companyNumber } = deriveIdentityFields(facts);
97	
98	  return {
99	    meta: { domain, sector: sectorFamily || null },
100	    identity: { legal_name: legalName, company_number: companyNumber },
101	    jurisdiction: { bound },
102	    // The facts layer produces no frameworks and no findings: those stages live downstream. Passing
103	    // empty lists makes every expected framework / known breach an honest abstention and lets every
104	    // known_non_breach read as correctly-not-asserted, exactly as the three-state doctrine requires.
105	    frameworks: [],
106	    findings: [],
107	  };
108	}
109	
110	// A shallow firm clone whose expected.sector is canonicalised to the same family vocabulary the
111	// engine emits, so the reference alias ('legal') and the engine family ('law-firms') compare equal.
112	function canonicaliseFirm(firm) {
113	  const exp = (firm && firm.expected) || {};
114	  return Object.assign({}, firm, {
115	    expected: Object.assign({}, exp, {
116	      sector: exp.sector != null ? canonSector(exp.sector) : exp.sector,
117	    }),
118	  });
119	}
120	
121	// subSectorTokensMatch(a, b) -> true when two normalised tokens agree exactly or one contains the
122	// other (loose match; both non-empty). Boolean lives in a RETURN, not a ternary test (COND guard).
123	function subSectorTokensMatch(a, b) {
124	  if (!a || !b) return false;
125	  return a === b || a.includes(b) || b.includes(a);
126	}
127	
128	// The informational sub-sector read: match if the engine's mid-tier sector descriptor agrees with
129	// the verified sub-sector under a loose token compare; otherwise ABSTAIN. It never contradicts.
130	function subSectorNote(emitted, expectedSub) {
131	  if (expectedSub == null) return null; // set does not pin a sub-sector
132	  if (!emitted || !emitted.sector) return 'abstain';
133	  const famKey = sector.familyOf(TREE, emitted.sector);
134	  // The engine descriptor the reference sub-sector corresponds to: the sub-family node when the
135	  // emitted sector sits under a family, else the emitted leaf sub_sector.
136	  const descriptor = emitted.sector === famKey ? emitted.sub_sector : emitted.sector;
137	  if (!descriptor) return 'abstain';
138	  const norm = (s) => String(s).toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
139	  const a = norm(descriptor);
140	  const b = norm(expectedSub);
141	  return subSectorTokensMatch(a, b) ? 'match' : 'abstain';
142	}
143	
144	// predicateIsPresent(pred) -> true when a capability predicate entry is marked present.
145	function predicateIsPresent(pred) {
146	  return pred && pred.present === 'yes';
147	}
148	function capsSummary(caps) {
149	  const preds = caps && caps.predicates ? caps.predicates : {};
150	  let present = 0;
151	  let total = 0;
152	  for (const k of Object.keys(preds)) {
153	    total++;
154	    if (predicateIsPresent(preds[k])) present++;
155	  }
156	  return { present, total };
157	}
158	
159	// pageHasVisibleText(page) -> true when a page object carries non-empty visible text (named so
160	// Array.prototype.some can take it directly; an inline arrow rolls complexity into the caller).
161	function pageHasVisibleText(page) {
162	  return page && typeof page.text === 'string' && page.text.trim() !== '';
163	}
164	// footerHasVisibleText(corpus) -> true when the corpus's footerText carries non-empty visible text.
165	function footerHasVisibleText(corpus) {
166	  return typeof corpus.footerText === 'string' && corpus.footerText.trim() !== '';
167	}
168	
169	// hasReadableCorpus(bundle) -> true when the bundle carries OBSERVED VISIBLE TEXT: at least one page
170	// with non-empty text, or a non-empty footerText. Readability is a property of observed text, never
171	// of page COUNT: a bundle of blank page objects is NOT readable, and footer-only evidence with no
172	// pages IS. This mirrors facts/capabilities.js buildSurfaces, which scans exactly these surfaces, so
173	// the harness and the capabilities door agree on what "readable" means. Absence of readable text and
174	// presence of unreadable evidence must never be conflated (CR: absence != observation).
175	function hasReadableCorpus(bundle) {
176	  const corpus = bundle && bundle.corpus;
177	  if (!corpus || typeof corpus !== 'object') return false;
178	  const pages = Array.isArray(corpus.pages) ? corpus.pages : [];
179	  const hasPageText = pages.some(pageHasVisibleText);
180	  const hasFooterText = footerHasVisibleText(corpus);
181	  return hasPageText || hasFooterText;
182	}
183	
184	// bundleHasPagesArray(bundle) -> true when bundle.corpus.pages exists and is an array (RETURN, not a ternary test - COND guard).
185	function bundleHasPagesArray(bundle) {
186	  return bundle && bundle.corpus && Array.isArray(bundle.corpus.pages);
187	}
188	// deriveFactsForBundle(bundle, hasCorpus) -> the four facts doors' output for one bundle.
189	// deriveCapabilities requires a scannable pages array by contract, so on a bundle with no pages to
190	// scan (footer-only, or an unreadable bundle) capabilities is simply not applicable (null) rather
191	// than invoked - it is NOT an error.
192	function deriveFactsForBundle(bundle, hasCorpus) {
193	  const pages = bundleHasPagesArray(bundle) ? bundle.corpus.pages : [];
194	  const canDeriveCaps = hasCorpus && pages.length > 0;
195	  return {
196	    identity: identity.resolveIdentity(bundle),
197	    jurisdiction: jurisdiction.resolveJurisdiction(bundle),
198	    sector: sector.resolveSector(bundle),
199	    capabilities: canDeriveCaps ? capabilities.deriveCapabilities(bundle) : null,
200	  };
201	}
202	
203	// buildFirmResultRow(ctx) -> the final per-firm row. ctx = {firm, facts, payload, report,
204	// bundleUnreachable}, bundled (not exported; only caller is the call site below).
205	function buildFirmResultRow(ctx) {
206	  const { firm, facts, payload, report, bundleUnreachable } = ctx;
207	  const emitted = facts.sector && facts.sector.value;
208	  const emittedFamily = payload.meta.sector;
209	  const sub = subSectorNote(emitted, firm.expected && firm.expected.sub_sector);
210	  const caps = facts.capabilities ? capsSummary(facts.capabilities) : null;
211	
212	  return {
213	    domain: firm.domain,
214	    role: firm.role,
215	    status: report.ok ? 'OK' : 'CONTRADICT',
216	    report,
217	    bundle_unreachable: bundleUnreachable,
218	    sector_family: emittedFamily,
219	    sector_node: emitted ? emitted.sector : null,
220	    sub_sector_note: sub,
221	    bound: payload.jurisdiction.bound,
222	    caps,
223	  };
224	}
225	
226	// Per-firm run. Returns a row; throws only escape to the caller which records them as ERROR rows.
227	// assertSafeDomain(domain) -> throws on an unsafe path component before path.join (traversal guard).
228	function assertSafeDomain(domain) {
229	  if (!/^[a-z0-9][a-z0-9.-]{0,251}$/i.test(domain)) {
230	    throw new Error('unsafe path component: ' + JSON.stringify(domain));
231	  }
232	}
233	
234	function runFirm(firm, fixturesDir) {
235	  assertSafeDomain(firm.domain);
236	  const fixturePath = path.join(fixturesDir, firm.domain + '.json');
237	  if (!fs.existsSync(fixturePath)) {
238	    // A verified firm with NO captured artefact on disk is an uncovered gap, not an abstention. Only
239	    // an explicitly captured unreachable bundle (a fixture that exists and is bot-walled / a SPA
240	    // shell) may abstain; a missing file evaluated nothing and must fail closed (CR: missing files
241	    // must fail; absence of a check is never a clean result).
242	    return { domain: firm.domain, role: firm.role, status: 'MISSING', detail: 'no fixture on disk - a verified firm with no captured artefact is an uncovered gap, not an abstention', report: null };
243	  }
244	
245	  let bundle;
246	  try {
247	    bundle = JSON.parse(fs.readFileSync(fixturePath, 'utf8'));
248	  } catch (e) {
249	    return { domain: firm.domain, role: firm.role, status: 'ERROR', detail: 'fixture unreadable: ' + e.message, report: null };
250	  }
251	
252	  // A door throwing on a bundle that DOES carry a corpus is a real integration breakage and
253	  // surfaces as ERROR below; the tolerant doors (identity/jurisdiction/sector) abstain across the
254	  // board on a corpus-less bundle instead.
255	  const hasCorpus = hasReadableCorpus(bundle);
256	  const bundleUnreachable = !hasCorpus || bundle.unreachable === true;
257	
258	  let facts;
259	  try {
260	    facts = deriveFactsForBundle(bundle, hasCorpus);
261	  } catch (e) {
262	    return { domain: firm.domain, role: firm.role, status: 'ERROR', detail: 'a facts door threw: ' + e.message, report: null };
263	  }
264	
265	  const payload = factsToPayload(firm.domain, facts);
266	  const report = verifyPayload(payload, canonicaliseFirm(firm));
267	
268	  return buildFirmResultRow({ firm, facts, payload, report, bundleUnreachable });
269	}
270	
271	// -------------------------------------------------------------------------------------------------
272	// Table + summary rendering.
273	// -------------------------------------------------------------------------------------------------
274	function statusOf(report, check) {
275	  if (!report) return '-';
276	  if (report.contradictions.some((c) => c.check === check)) return 'CONTRADICT';
277	  if (report.matches.some((m) => m.check === check)) return 'match';
278	  if (report.abstentions.some((a) => a.check === check)) return 'abstain';
279	  return '-';
280	}
281	
282	function pad(s, n) {
283	  s = String(s == null ? '' : s);
284	  return s.length >= n ? s : s + ' '.repeat(n - s.length);
285	}
286	
287	// printPlaceholderRow(r, W, status) -> the placeholder row for UNREACHABLE/ERROR/MISSING statuses
288	// (the status label that varies between the original two inline blocks is now a parameter).
289	function printPlaceholderRow(r, W, status) {
290	  console.log([pad(r.domain, W[0]), pad(r.role, W[1]), pad('-', W[2]), pad('-', W[3]), pad('-', W[4]), pad('-', W[5]), pad(status, W[6])].join(' '));
291	}
292	
293	// sectorCellText(sec) -> the sector column cell text (CONTRADICT stays CONTRADICT, else as-is).
294	function sectorCellText(sec) {
295	  return sec === 'CONTRADICT' ? 'CONTRADICT' : sec;
296	}
297	// formatJurCell(jur, bound) -> the jurisdiction cell: CONTRADICT stays bare, else the label is
298	// suffixed with the bound jurisdiction codes when there are any.
299	function formatJurCell(jur, bound) {
300	  if (jur === 'CONTRADICT') return jur;
301	  return bound.length ? jur + ':' + bound.join('/') : jur;
302	}
303	
304	// printFirmRow(r, W) -> the full data row for a firm that actually ran (not UNREACHABLE/ERROR/MISSING).
305	function printFirmRow(r, W) {
306	  const sec = statusOf(r.report, 'sector');
307	  const jur = statusOf(r.report, 'jurisdictions_bound');
308	  const capCell = r.caps ? (r.caps.present + '/' + r.caps.total) : 'n/a';
309	  const resultCell = r.status === 'OK' && r.bundle_unreachable ? 'OK*' : r.status;
310	  console.log([
311	    pad(r.domain, W[0]),
312	    pad(r.role, W[1]),
313	    pad(sectorCellText(sec), W[2]),
314	    pad(r.sub_sector_note || '-', W[3]),
315	    pad(formatJurCell(jur, r.bound), W[4]),
316	    pad(capCell, W[5]),
317	    pad(resultCell, W[6]),
318	  ].join(' '));
319	}
320	
321	function printTable(rows) {
322	  const H = ['domain', 'role', 'sector', 'sub', 'jur', 'caps', 'result'];
323	  const W = [28, 10, 12, 9, 12, 7, 11];
324	  console.log(H.map((h, i) => pad(h, W[i])).join(' '));
325	  console.log(W.map((w) => '-'.repeat(w)).join(' '));
326	  for (const r of rows) {
327	    if (r.status === 'UNREACHABLE') { printPlaceholderRow(r, W, 'UNREACHABLE'); continue; }
328	    if (r.status === 'ERROR' || r.status === 'MISSING') { printPlaceholderRow(r, W, r.status); continue; }
329	    printFirmRow(r, W);
330	  }
331	}
332	
333	function summarise(rows) {
334	  let matches = 0;
335	  let abstentions = 0;
336	  let contradictions = 0;
337	  for (const r of rows) {
338	    if (!r.report) continue;
339	    matches += r.report.matches.length;
340	    abstentions += r.report.abstentions.length;
341	    contradictions += r.report.contradictions.length;
342	  }
343	  return {
344	    firms: rows.length,
345	    ok: rows.filter((r) => r.status === 'OK').length,
346	    contradicting: rows.filter((r) => r.status === 'CONTRADICT').length,
347	    unreachable: rows.filter((r) => r.status === 'UNREACHABLE').length,
348	    missing: rows.filter((r) => r.status === 'MISSING').length,
349	    errored: rows.filter((r) => r.status === 'ERROR').length,
350	    matches,
351	    abstentions,
352	    contradictions,
353	  };
354	}
355	
356	// -------------------------------------------------------------------------------------------------
357	// CLI.
358	// -------------------------------------------------------------------------------------------------
359	// parseRunFactsArgs(argv) -> {opts} on success, or {exitCode} on an unrecognised argument.
360	function parseRunFactsArgs(argv) {
361	  const args = argv.slice(2);
362	  const opts = { json: false, set: DEFAULT_SET, fixtures: DEFAULT_FIXTURES, domain: null };
363	  for (let i = 0; i < args.length; i++) {
364	    const a = args[i];
365	    if (a === '--json') { opts.json = true; continue; }
366	    if (a === '--set') { opts.set = args[++i]; continue; }
367	    if (a === '--fixtures') { opts.fixtures = args[++i]; continue; }
368	    if (a === '--domain') { opts.domain = args[++i]; continue; }
369	    console.error('Unknown argument: ' + a);
370	    return { exitCode: 2 };
371	  }
372	  return { opts };
373	}
374	
375	// loadRefSetAndFixtures(opts) -> {refSet} on success, or {exitCode} when the reference set cannot
376	// be read or the fixtures directory does not exist.
377	function loadRefSetAndFixtures(opts) {
378	  let refSet;
379	  try {
380	    refSet = loadReferenceSet(opts.set);
381	  } catch (e) {
382	    console.error('Cannot read reference set ' + opts.set + ': ' + e.message);
383	    return { exitCode: 2 };
384	  }
385	  if (!fs.existsSync(opts.fixtures)) {
386	    console.error('Fixtures directory not found: ' + opts.fixtures);
387	    return { exitCode: 2 };
388	  }
389	  // Fail closed on an existing-but-empty fixtures directory: it would otherwise produce only MISSING
390	  // rows and, before this guard, a misleading clean exit. A gate that evaluated no artefacts has not
391	  // run (CR: never report a clean result for a check that never ran).
392	  const fixtureFiles = fs.readdirSync(opts.fixtures).filter((f) => f.endsWith('.json'));
393	  if (fixtureFiles.length === 0) {
394	    console.error('Fixtures directory is empty (no .json bundles): ' + opts.fixtures + ' - nothing to evaluate, so the run cannot report a clean result.');
395	    return { exitCode: 2 };
396	  }
397	  return { refSet };
398	}
399	
400	// selectFirms(refSet, opts) -> {firms} on success, or {exitCode} when --domain names a firm not
401	// in the reference set.
402	function selectFirms(refSet, opts) {
403	  let firms = refSet.firms || [];
404	  // Fail closed on an empty firm set: a reference-set gate with nobody to check evaluated nothing.
405	  if (firms.length === 0) {
406	    console.error('Reference set has an empty firms[] array - nothing to check, so the run cannot report a clean result.');
407	    return { exitCode: 2 };
408	  }
409	  if (opts.domain) {
410	    const found = findFirm(refSet, opts.domain);
411	    if (!found) {
412	      console.error('Domain "' + opts.domain + '" is not in the reference set.');
413	      return { exitCode: 2 };
414	    }
415	    firms = [found];
416	  }
417	  return { firms };
418	}
419	
420	// printContradictionDetail(rows) -> the "contradictions (each fails the gate):" block.
421	function printContradictionDetail(rows) {
422	  console.log('\ncontradictions (each fails the gate):');
423	  for (const r of rows) {
424	    if (!r.report) continue;
425	    for (const c of r.report.contradictions) {
426	      console.log('  FAIL  ' + r.domain + '  [' + c.check + ']  ' + c.detail);
427	    }
428	  }
429	}
430	// resultLine(summary) -> the final RESULT: line (sequential ifs, not the original nested ternary).
431	function resultLine(summary) {
432	  if (summary.errored > 0 || summary.missing > 0) {
433	    return 'RESULT: ERROR - a facts door threw, a fixture was unreadable, or a verified firm had no captured fixture (uncovered gap)';
434	  }
435	  if (summary.contradictions > 0) {
436	    return 'RESULT: CONTRADICTION - the facts layer contradicted hand-verified ground truth';
437	  }
438	  return 'RESULT: OK (no contradictions; abstentions and unreachable fixtures allowed)';
439	}
440	// printHumanReport(rows, summary, errored) -> the full non-JSON report: header, table, legend,
441	// summary counts, contradiction detail and error detail.
442	function printHumanReport(rows, summary, errored) {
443	  console.log('reference-set run-facts: the four facts doors vs hand-verified ground truth');
444	  console.log('law: match or abstain, never contradict (canonicalised through facts/vocabulary.js)\n');
445	  printTable(rows);
446	  const unreachableBundles = rows.filter((r) => r.status === 'OK' && r.bundle_unreachable).length;
447	  console.log('');
448	  console.log('legend: match/abstain per the reference law; OK* = reachable-firm expectations met by '
449	    + 'abstention because the fixture bundle is unreachable (bot-walled / SPA shell); caps n/a = no corpus to derive from');
450	  console.log('summary: ' + summary.firms + ' firms | ' + summary.ok + ' ok (' + unreachableBundles + ' on unreachable bundles) | '
451	    + summary.contradicting + ' contradicting | ' + summary.missing + ' missing-fixture | ' + summary.errored + ' errored');
452	  console.log('         ' + summary.matches + ' matches, ' + summary.abstentions + ' abstentions (allowed), '
453	    + summary.contradictions + ' contradictions');
454	  if (summary.contradictions > 0) printContradictionDetail(rows);
455	  for (const r of errored) console.log('\nERROR  ' + r.domain + ': ' + r.detail);
456	  console.log('');
457	  console.log(resultLine(summary));
458	}
459	
460	// exitCodeFor(summary) -> exit code for a completed run: 2 on ERROR/MISSING (gate did not fully
461	// run), else 1 on any contradiction, else 0.
462	function exitCodeFor(summary) {
463	  if (summary.errored > 0 || summary.missing > 0) return 2;
464	  return summary.contradictions > 0 ? 1 : 0;
465	}
466	
467	function main(argv) {
468	  const parsed = parseRunFactsArgs(argv);
469	  if (parsed.exitCode) return parsed.exitCode;
470	  const { opts } = parsed;
471	
472	  const loaded = loadRefSetAndFixtures(opts);
473	  if (loaded.exitCode) return loaded.exitCode;
474	  const { refSet } = loaded;
475	
476	  const selected = selectFirms(refSet, opts);
477	  if (selected.exitCode) return selected.exitCode;
478	  const { firms } = selected;
479	
480	  const rows = firms.map((f) => runFirm(f, opts.fixtures));
481	  const summary = summarise(rows);
482	  const errored = rows.filter((r) => r.status === 'ERROR');
483	
484	  if (opts.json) {
485	    console.log(JSON.stringify({ summary, rows }, null, 2));
486	  } else {
487	    printHumanReport(rows, summary, errored);
488	  }
489	
490	  return exitCodeFor(summary);
491	}
492	
493	if (require.main === module) {
494	  process.exit(main(process.argv));
495	}
