178	    documents: { records: docResult.documents, unparsed: docResult.unparsed },
179	    coverage: buildCoverage(pages, opts, truncated, docResult.unparsedClasses),
180	    telemetry: { ...telemetry, pages_captured: pages.length, truncated, via: unreachable ? 'none' : 'direct' },
