206	  ForStatement: walkLoop,
207	  ForInStatement: walkLoop,
208	  ForOfStatement: walkLoop,
209	  WhileStatement: walkLoop,
210	  DoWhileStatement: walkLoop,
211	  SwitchStatement: walkSwitch,
212	  TryStatement: walkTry,
213	  LogicalExpression: walkLogical,
214	  ConditionalExpression: walkConditional,
