308	    if (!didThrow(() => scanContent('selftest-' + label + '.js', src))) {
309	      return { pass: false, detail: 'heuristic fallback did NOT refuse ' + label + ' input - it must never under-report (acorn is mandatory)' };
310	    }
311	  }
312	  return { pass: true, detail: 'heuristic fallback correctly REFUSES all input (acorn mandatory; under-reporting is an unearned zero)' };
313	}
