336	  const r = scanContent('selftest.js', src);
337	  const kinds = new Set(r.violations.map((v) => v.kind));
338	  const functionCaps = ['long-function', 'deep-nesting', 'high-branching', 'too-many-params'];
339	  const wantFunctionCaps = functionCaps.every((k) => kinds.has(k));
340	
341	  // The fifth cap (large-file) is file-length, not function-shape: exercise it with a synthetic
342	  // 501-line source so a regression disabling the file-length check fails the self-test.
343	  const bigSrc = Array.from({ length: 501 }, (_, i) => `const v${i} = ${i};`).join('\n') + '\n';
344	  const hasLargeFile = scanContent('selftest-big.js', bigSrc).violations.some((v) => v.kind === 'large-file');
345	
346	  const cleanScan = scanContent('selftest-clean.js', 'const clean = (x) => x + 1;\nfunction ok(a) { return a; }\n');
347	  const pass = wantFunctionCaps && hasLargeFile && cleanScan.violations.length === 0;
