#!/usr/bin/env node
'use strict';
/**
 * eval/e2e/run-pipeline.js - THE P3 exit-criteria end-to-end harness (docs/P3-ACCEPTANCE.md, P3 exit).
 *
 * Pipeline per firm: fixtureBundle (eval/reference-set/fixtures/ real crawled fixtures, plus this
 * directory's own synthetic additions) -> facts (facts/identity.js + jurisdiction.js + sector.js +
 * capabilities.js, real calls) -> coverage (evidence/crawler/coverage-contract.js against the compiled
 * catalogue) -> propose (breach/proposers/ if landed) -> verify (breach/verifiers/ if landed) ->
 * adjudicate (breach/adjudicator/ if landed, with an injected SCRIPTED llmCall - no network call is
 * ever made from this harness) -> findings[].
 *
 * Judgement against eval/reference-set/reference-set.json's hand-verified expectations reuses
 * eval/reference-set/verify.js's verifyPayload() (match-or-abstain-never-contradict) unmodified, and
 * layers the reproduced/missed/skipped and contradiction/clean distinctions docs/P3-ACCEPTANCE.md asks
 * for (eval/e2e/lib/judge.js). A skipped stage can never fabricate a pass (caution.md C-037): every
 * output here is honest about what actually ran today.
 *
 * Usage:
 *   node eval/e2e/run-pipeline.js
 *   node eval/e2e/run-pipeline.js --domain neuclinic.co.uk
 *   node eval/e2e/run-pipeline.js --json
 *   node eval/e2e/run-pipeline.js --no-synthetic --no-red-team
 *   node eval/e2e/run-pipeline.js --set <reference-set.json> --fixtures <dir> --synthetic <dir> --red-team <file>
 *
 * Suggested package.json script (package.json is not owned by this task; add by hand):
 *   "e2e": "node eval/e2e/run-pipeline.js"
 *
 * Exit codes: 0 = zero contradictions AND zero red-team escapes/errors among entries that actually ran.
 *             1 = at least one contradiction, or at least one red-team escape/error.
 *             2 = usage/data error (bad argument, unreadable reference set, empty/missing fixtures dir,
 *                 a reference-set firm with no fixture on disk, or a facts/coverage door that threw).
 */

const fs = require('fs');
const path = require('path');

const { loadRefSetAndFixtures, selectFirms } = require('../reference-set/run-facts.js');
const { runPipeline, probeStageWiring } = require('./lib/pipeline.js');
const { judgeFirm } = require('./lib/judge.js');
const { loadSyntheticFixtures } = require('./lib/synthetic-fixtures.js');
const { runRedTeamLane } = require('./lib/redteam.js');
const report = require('./lib/report.js');

const DEFAULT_SET = path.join(__dirname, '..', 'reference-set', 'reference-set.json');
const DEFAULT_FIXTURES = path.join(__dirname, '..', 'reference-set', 'fixtures');
const DEFAULT_SYNTHETIC = path.join(__dirname, 'fixtures');
const DEFAULT_REDTEAM = path.join(__dirname, '..', 'red-team', 'fixtures.json');

// assertSafeDomain(domain) -> throws on an unsafe path component before path.join (traversal guard;
// mirrors eval/reference-set/run-facts.js's own private guard, which is not exported).
function assertSafeDomain(domain) {
  if (!/^[a-z0-9][a-z0-9.-]{0,251}$/i.test(domain)) {
    throw new Error('unsafe path component: ' + JSON.stringify(domain));
  }
}

// loadFixtureBundle(fixturesDir, domain) -> {bundle} or {missing:true}. Never throws on a missing file;
// a malformed JSON file is left to throw (surfaced by the caller as an ERROR row, not silently skipped).
function loadFixtureBundle(fixturesDir, domain) {
  assertSafeDomain(domain);
  const p = path.join(fixturesDir, domain + '.json');
  if (!fs.existsSync(p)) return { missing: true };
  return { bundle: JSON.parse(fs.readFileSync(p, 'utf8')) };
}

// judgedRow(firm, pipelineResult) -> the report row: the judged fields plus this firm's own stageTable
// (so --json carries full per-firm detail even though the human report's header line uses the probed
// wiring once, up front).
function judgedRow(firm, pipelineResult) {
  const judged = judgeFirm(firm, pipelineResult);
  return Object.assign({ stageTable: pipelineResult.stageTable }, judged);
}

async function runOneFirm(firm, fixturesDir) {
  const loaded = loadFixtureBundle(fixturesDir, firm.domain);
  if (loaded.missing) {
    return { domain: firm.domain, role: firm.role, error: 'no fixture on disk (uncovered gap - a verified firm with no captured artefact)' };
  }
  let pipelineResult;
  try {
    pipelineResult = await runPipeline(firm.domain, loaded.bundle);
  } catch (e) {
    return { domain: firm.domain, role: firm.role, error: 'pipeline threw: ' + e.message };
  }
  return judgedRow(firm, pipelineResult);
}

async function runOneSynthetic(fx) {
  if (fx.error) return { domain: fx.file, role: 'synthetic', error: fx.error };
  const firm = { domain: fx.domain, role: fx.role, expected: fx.expected };
  let pipelineResult;
  try {
    pipelineResult = await runPipeline(fx.domain, fx.bundle);
  } catch (e) {
    return { domain: fx.domain, role: fx.role, error: 'pipeline threw: ' + e.message };
  }
  return judgedRow(firm, pipelineResult);
}

async function runSyntheticFixtures(dir) {
  const fixtures = loadSyntheticFixtures(dir);
  const rows = [];
  for (const fx of fixtures) rows.push(await runOneSynthetic(fx));
  return rows;
}

const FLAGS_WITH_VALUE = {
  '--set': 'set', '--fixtures': 'fixtures', '--synthetic': 'synthetic', '--red-team': 'redteam', '--domain': 'domain',
};

function parseOneArg(args, i, opts) {
  const a = args[i];
  if (a === '--json') { opts.json = true; return 1; }
  if (a === '--no-synthetic') { opts.noSynthetic = true; return 1; }
  if (a === '--no-red-team') { opts.noRedteam = true; return 1; }
  const key = FLAGS_WITH_VALUE[a];
  if (key) { opts[key] = args[i + 1]; return 2; }
  return 0;
}

// parseArgs(argv) -> {opts} on success, or {exitCode} when an unrecognised argument is given.
function parseArgs(argv) {
  const args = argv.slice(2);
  const opts = {
    json: false, set: DEFAULT_SET, fixtures: DEFAULT_FIXTURES, synthetic: DEFAULT_SYNTHETIC,
    redteam: DEFAULT_REDTEAM, domain: null, noSynthetic: false, noRedteam: false,
  };
  for (let i = 0; i < args.length;) {
    const consumed = parseOneArg(args, i, opts);
    if (consumed === 0) { console.error('Unknown argument: ' + args[i]); return { exitCode: 2 }; }
    i += consumed;
  }
  return { opts };
}

// exitCodeFor(rows, redteam) -> 2 on any ERROR row (a gate that did not fully run), else 1 on any
// contradiction or red-team escape/error, else 0. Mirrors eval/reference-set/run-facts.js's own
// severity ordering (errored/missing outranks a contradiction: an ungraded check is worse than a
// graded failure).
function exitCodeFor(rows, redteam) {
  if (rows.some((r) => r.error)) return 2;
  const contradicting = rows.some((r) => r.contradiction);
  const redRows = redteam.rows || [];
  const escapes = redRows.some((r) => r.status === 'escaped' || r.status === 'error');
  return (contradicting || escapes) ? 1 : 0;
}

async function runReferenceSetFirms(opts) {
  const loaded = loadRefSetAndFixtures({ set: opts.set, fixtures: opts.fixtures });
  if (loaded.exitCode) return { exitCode: loaded.exitCode };
  const selected = selectFirms(loaded.refSet, { domain: opts.domain });
  if (selected.exitCode) return { exitCode: selected.exitCode };
  const rows = [];
  for (const firm of selected.firms) rows.push(await runOneFirm(firm, opts.fixtures));
  return { rows };
}

async function main(argv) {
  const parsed = parseArgs(argv);
  if (parsed.exitCode) return parsed.exitCode;
  const { opts } = parsed;

  const referenceRun = await runReferenceSetFirms(opts);
  if (referenceRun.exitCode) return referenceRun.exitCode;

  const syntheticRows = opts.noSynthetic ? [] : await runSyntheticFixtures(opts.synthetic);
  const allRows = referenceRun.rows.concat(syntheticRows);

  const wiring = probeStageWiring();
  const redteam = opts.noRedteam ? { present: false, rows: [] } : await runRedTeamLane(opts.redteam, {
    stageTable: wiring.map((w) => ({ stage: w.stage, status: w.status === 'wired' ? 'ran' : 'skipped' })),
    fixturesDir: opts.fixtures,
    runPipelineForBundle: (domain, bundle) => runPipeline(domain, bundle),
  });

  const summary = report.summarise(allRows, redteam);
  if (opts.json) {
    console.log(JSON.stringify({ stageWiring: wiring, rows: allRows, redteam, summary }, null, 2));
  } else {
    report.printHumanReport(wiring, allRows, redteam, summary);
  }
  return exitCodeFor(allRows, redteam);
}

if (require.main === module) {
  main(process.argv).then((code) => process.exit(code));
}

module.exports = { main, parseArgs, runOneFirm, runOneSynthetic, runSyntheticFixtures, loadFixtureBundle, exitCodeFor };

'use strict';
// eval/e2e/run-pipeline.test.js - unit tests for the CLI's own small pieces, PLUS a smoke test that
// executes the REAL entry point (caution.md C-148: "every eval suite includes a smoke test that
// executes the real entry point; tests that assert on source text are not counted as coverage").
//   node --test eval/e2e/run-pipeline.test.js

const test = require('node:test');
const assert = require('node:assert');
const fs = require('fs');
const os = require('os');
const path = require('path');

const { main, parseArgs, loadFixtureBundle, runOneFirm, runOneSynthetic, exitCodeFor } = require('./run-pipeline');

test('parseArgs: defaults point at the real reference-set + this directory\'s own fixtures/red-team paths', () => {
  const { opts } = parseArgs(['node', 'run-pipeline.js']);
  assert.ok(opts.set.endsWith(path.join('reference-set', 'reference-set.json')));
  assert.ok(opts.fixtures.endsWith(path.join('reference-set', 'fixtures')));
  assert.ok(opts.synthetic.endsWith(path.join('e2e', 'fixtures')));
  assert.ok(opts.redteam.endsWith(path.join('red-team', 'fixtures.json')));
  assert.strictEqual(opts.json, false);
});

test('parseArgs: --json, --domain, --no-synthetic, --no-red-team are parsed', () => {
  const { opts } = parseArgs(['node', 'run-pipeline.js', '--json', '--domain', 'example.com', '--no-synthetic', '--no-red-team']);
  assert.strictEqual(opts.json, true);
  assert.strictEqual(opts.domain, 'example.com');
  assert.strictEqual(opts.noSynthetic, true);
  assert.strictEqual(opts.noRedteam, true);
});

test('parseArgs: an unrecognised argument fails closed with exit code 2', () => {
  const r = parseArgs(['node', 'run-pipeline.js', '--not-a-real-flag']);
  assert.strictEqual(r.exitCode, 2);
});

test('loadFixtureBundle: a missing fixture is reported {missing:true}, never a throw', () => {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'e2e-cli-'));
  const r = loadFixtureBundle(dir, 'nope.example');
  assert.strictEqual(r.missing, true);
});

test('loadFixtureBundle: an unsafe domain is rejected before touching the filesystem', () => {
  assert.throws(() => loadFixtureBundle('/tmp', '../../etc/passwd'));
});

test('loadFixtureBundle: a present fixture is parsed and returned', () => {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'e2e-cli-'));
  fs.writeFileSync(path.join(dir, 'example.com.json'), JSON.stringify({ domain: 'example.com', corpus: { pages: [] } }));
  const r = loadFixtureBundle(dir, 'example.com');
  assert.deepStrictEqual(r.bundle, { domain: 'example.com', corpus: { pages: [] } });
});

test('runOneFirm: a firm with no fixture on disk is an ERROR row (an uncovered gap, not an abstention)', async () => {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'e2e-cli-'));
  const row = await runOneFirm({ domain: 'ghost.example', role: 'test', expected: {} }, dir);
  assert.match(row.error, /no fixture on disk/);
});

test('runOneFirm: a real bundle judges cleanly against an expectation with nothing to check', async () => {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'e2e-cli-'));
  fs.writeFileSync(path.join(dir, 'blank.example.json'), JSON.stringify({ domain: 'blank.example', corpus: { pages: [] } }));
  const row = await runOneFirm({ domain: 'blank.example', role: 'test', expected: {} }, dir);
  assert.strictEqual(row.error, undefined);
  assert.strictEqual(row.contradiction, false);
});

test('runOneSynthetic: a fixture-load error is passed through as a row error', async () => {
  const row = await runOneSynthetic({ file: 'broken.json', error: 'unreadable JSON: x' });
  assert.strictEqual(row.error, 'unreadable JSON: x');
  assert.strictEqual(row.domain, 'broken.json');
});

test('runOneSynthetic: a well-formed synthetic bundle runs the real pipeline and judges honestly', async () => {
  const fx = {
    domain: 'synthetic-cli-test.example',
    role: 'synthetic',
    bundle: { domain: 'synthetic-cli-test.example', corpus: { pages: [{ url: 'https://x/', text: 'hello world' }] } },
    expected: { known_breaches: [{ id: 'X', framework: 'X', match_any: ['should-never-appear'] }] },
  };
  const row = await runOneSynthetic(fx);
  assert.strictEqual(row.error, undefined);
  assert.strictEqual(row.knownBreaches[0].status, 'skipped', 'the breach lane is not fully wired today, so this must be skipped, never missed or reproduced');
});

test('exitCodeFor: an ERROR row outranks everything else (exit 2)', () => {
  assert.strictEqual(exitCodeFor([{ error: 'x' }, { contradiction: true }], { rows: [] }), 2);
});

test('exitCodeFor: a contradiction with no errors is exit 1', () => {
  assert.strictEqual(exitCodeFor([{ contradiction: true }], { rows: [] }), 1);
});

test('exitCodeFor: a red-team escape with no errors or contradictions is exit 1', () => {
  assert.strictEqual(exitCodeFor([{ contradiction: false }], { rows: [{ status: 'escaped' }] }), 1);
});

test('exitCodeFor: a red-team error (pipeline crash on adversarial input) is also exit 1', () => {
  assert.strictEqual(exitCodeFor([{ contradiction: false }], { rows: [{ status: 'error' }] }), 1);
});

test('exitCodeFor: clean rows and a fully-caught red-team lane is exit 0', () => {
  assert.strictEqual(exitCodeFor([{ contradiction: false }], { rows: [{ status: 'caught' }, { status: 'skipped' }] }), 0);
});

// ---------------------------------------------------------------------------------------------------
// SMOKE TEST: executes the REAL entry point (caution.md C-148). Runs against the real, committed
// eval/reference-set/ fixtures and this directory's own real synthetic fixture, with the red-team lane
// and synthetic additions both exercised (no --no-* flags), --json so the assertions are on structure,
// not printed text. This is the test that would have caught a ReferenceError/TDZ crash inside main()
// that a purely-mocked unit test could never see.
// ---------------------------------------------------------------------------------------------------
test('SMOKE: node eval/e2e/run-pipeline.js (via its real main()) runs end-to-end against the real fixtures', async () => {
  const originalLog = console.log;
  const lines = [];
  console.log = (...args) => lines.push(args.join(' '));
  let code;
  try {
    code = await main(['node', 'eval/e2e/run-pipeline.js', '--json']);
  } finally {
    console.log = originalLog;
  }
  assert.ok(code === 0 || code === 1, 'expected a graded result (0 clean or 1 contradiction/escape), not a usage/data error: got ' + code);
  assert.strictEqual(lines.length, 1, 'expected exactly one JSON blob on stdout in --json mode');
  const parsed = JSON.parse(lines[0]);
  assert.ok(Array.isArray(parsed.stageWiring) && parsed.stageWiring.length === 5);
  assert.ok(Array.isArray(parsed.rows) && parsed.rows.length >= 27, 'expected the full 27-firm reference set plus synthetic additions');
  assert.ok(parsed.rows.some((r) => r.domain === 'example-synthetic-breach.test'), 'the synthetic fixture should have run alongside the reference-set firms');
  assert.strictEqual(typeof parsed.redteam.present, 'boolean');
  assert.strictEqual(parsed.summary.errored, 0, 'no firm should ERROR on the real, committed fixtures');
});

test('SMOKE: node eval/e2e/run-pipeline.js --domain <one firm> restricts the run and still executes cleanly', async () => {
  const originalLog = console.log;
  const lines = [];
  console.log = (...args) => lines.push(args.join(' '));
  let code;
  try {
    code = await main(['node', 'eval/e2e/run-pipeline.js', '--domain', 'neuclinic.co.uk', '--no-synthetic', '--no-red-team', '--json']);
  } finally {
    console.log = originalLog;
  }
  assert.ok(code === 0 || code === 1);
  const parsed = JSON.parse(lines[0]);
  assert.strictEqual(parsed.rows.length, 1);
  assert.strictEqual(parsed.rows[0].domain, 'neuclinic.co.uk');
});

test('SMOKE: an actual child-process invocation of the file exits with a stable code (proves the file itself is directly runnable, not only its exported main)', async () => {
  const { execFileSync } = require('child_process');
  const repoRoot = path.join(__dirname, '..', '..');
  let status = 0;
  try {
    execFileSync(process.execPath, [path.join(__dirname, 'run-pipeline.js'), '--domain', 'neuclinic.co.uk', '--no-synthetic', '--no-red-team', '--json'], { cwd: repoRoot, stdio: 'pipe' });
  } catch (e) {
    status = e.status;
  }
  assert.ok(status === 0 || status === 1, 'expected a graded exit code from the real child process, got ' + status);
});

