79	// choice, so it is exempt under reg.6(4)). Authored from framework/platform conventions.
80	const ESSENTIAL_COOKIE_PATTERNS = Object.freeze([
81	  { rx: /^phpsessid$/i, reason: 'PHP session' },
82	  { rx: /^jsessionid$/i, reason: 'Java session' },
83	  { rx: /^asp\.net_sessionid$/i, reason: 'ASP.NET session' },
84	  { rx: /^connect\.sid$/i, reason: 'Express session' },
85	  { rx: /^sessionid$/i, reason: 'application session' },
86	  { rx: /^csrftoken$/i, reason: 'CSRF token' },
87	  { rx: /^xsrf-token$/i, reason: 'CSRF token' },
88	  { rx: /^__host-/i, reason: 'host-locked security cookie' },
89	  { rx: /^__secure-/i, reason: 'secure-prefixed security cookie' },
90	  { rx: /^__cf_bm$|^cf_clearance$/i, reason: 'Cloudflare bot management / security' },
91	  { rx: /^wordpress_|^wp-settings|^wp_/i, reason: 'WordPress session/settings' },
92	  { rx: /^cookieconsent|^cookieyes-consent$|^optanonconsent$|^cookie_consent/i, reason: 'consent record (reg.6(4) exempt)' },
93	]);
94	
95	// hostLabels(host) -> the lowercased host split into labels, or [] for a non-string/empty host.
96	function hostLabels(host) {
97	  const h = String(host || '').toLowerCase().replace(/\.$/, '');
98	  if (!h) return [];
99	  return h.split('.');
100	}
101	
102	// isTrackerHost(host) -> true when `host` is, or is a subdomain of, a known tracker registrable
103	// domain. Parsed by label suffix (never a substring match): "www.google-analytics.com" matches the
104	// "google-analytics.com" entry; "www.bing.com" does NOT match the exact "bat.bing.com" entry.
105	function isTrackerHost(host) {
106	  const labels = hostLabels(host);
107	  if (labels.length === 0) return false;
108	  for (let i = 0; i < labels.length; i++) {
109	    if (TRACKER_HOSTS.has(labels.slice(i).join('.'))) return true;
110	  }
111	  return false;
112	}
113	
114	// matchFirst(name, patterns) -> the first matching pattern object, or null.
115	function matchFirst(name, patterns) {
116	  const n = String(name || '');
117	  for (const p of patterns) {
118	    if (p.rx.test(n)) return p;
119	  }
120	  return null;
121	}
122	
123	// classifyCookieName(name) -> { verdict, category, platform }.
124	//   verdict: 'essential'      strictly necessary; never a breach candidate.
125	//           'non_essential'  known tracker cookie; a consent-required breach candidate.
126	//           'unknown'        not recognised; ABSTAIN (Rule 6) - never a breach candidate.
127	function classifyCookieName(name) {
128	  if (matchFirst(name, ESSENTIAL_COOKIE_PATTERNS)) {
129	    return { verdict: 'essential', category: null, platform: null };
130	  }
131	  const tracker = matchFirst(name, TRACKER_COOKIE_PATTERNS);
132	  if (tracker) {
133	    return { verdict: 'non_essential', category: tracker.category, platform: tracker.platform };
134	  }
135	  return { verdict: 'unknown', category: null, platform: null };
136	}
137	
138	// classifyCookie(cookie) -> { verdict, category, platform, host }. Combines the name classifier
139	// with a tracker-host check on the cookie's own domain: an essential-named cookie stays essential,
140	// but an UNKNOWN-named cookie whose domain is a known tracker host is promoted to non_essential
141	// (a third-party tracker cookie under a bespoke name). A first-party unknown cookie stays unknown.
142	function classifyCookie(cookie) {
