25	const path = require('path');
26	
27	function normaliseEntries(data) {
28	  if (Array.isArray(data)) return data;
29	  if (data && Array.isArray(data.entries)) return data.entries;
30	  if (data && Array.isArray(data.fixtures)) return data.fixtures;
31	  return null;
