40	  } catch (e) {
41	    return { present: true, entries: [], parseError: e.message };
42	  }
43	  const entries = normaliseEntries(data);
44	  if (entries === null) {
45	    return { present: true, entries: [], parseError: 'unrecognised top-level shape (expected an array or {entries:[...]}/{fixtures:[...]})' };
