110	 * runRedTeamEntry(entry, ctx) -> {id, status:'caught'|'escaped'|'skipped'|'error', reason?}
111	 * ctx = { stageTable, fixturesDir, runPipelineForBundle: async (domain, bundle) => pipelineResult }
112	 */
