126	    // from a fabrication escaping - it is recorded loudly as 'error' (not 'skipped', not 'caught') so
127	    // a crash on adversarial input is never mistaken for the gate having held.
128	    return { id, status: 'error', reason: 'pipeline threw on this fixture: ' + e.message };
129	  }
