134	// (adversarial fixtures are expected to be few; sequential keeps error attribution unambiguous).
135	async function runRedTeamLane(filePath, ctx) {
136	  const loaded = loadRedTeamFixtures(filePath);
137	  if (!loaded.present) return { present: false, rows: [] };
138	  if (loaded.parseError) return { present: true, rows: [], parseError: loaded.parseError };
139	  const rows = [];
140	  for (const entry of loaded.entries) rows.push(await runRedTeamEntry(entry, ctx));
141	  return { present: true, rows };
142	}
