1	'use strict';
2	// eval/e2e/lib/judge.js - judges ONE pipeline run against its reference-set (or synthetic) expectation.
3	//
4	// Reuses eval/reference-set/verify.js's verifyPayload() (match-or-abstain-never-contradict, the
5	// existing facts-only harness's own comparator - NOT modified, only imported) as the base check for
6	// identity/sector/jurisdiction/expected_frameworks_min/known_breaches/known_non_breaches, and adds the
7	// one distinction a facts-only harness cannot make: WHY a known_breach was not reproduced.
8	//
9	// verify.js's own abstention is silent on that distinction (a missing finding is a missing finding,
10	// whether the pipeline ran fully and found nothing or never ran at all). This harness is not allowed
11	// to be silent about it (docs/P3-ACCEPTANCE.md point 4: "a skipped stage can never fabricate a pass").
12	//
13	//   reproduced    a known_breach's match_any tokens were found among the pipeline's findings.
14	//   missed        the FULL breach lane ran (propose+verify+adjudicate all genuinely executed) and
15	//                 still did not find it - an honest abstention, not a system fault.
16	//   skipped       one or more of propose/verify/adjudicate did not run for this firm (not landed yet,
17	//                 or errored), so "missed" would overclaim: the check never really happened.
18	//
19	//   contradiction a known_non_breach's match_any tokens were found among the findings (the P3 exit
20	//                 bar: zero false accusations). ANY hit here is fatal, whether or not the breach lane
21	//                 is complete - a partially-wired pipeline that already fabricates is not "not tested
22	//                 enough to fail", it has already failed.
23	//   clean         no such finding. `trivial:true` flags the case where the breach lane could not
24	//                 possibly have produced ANY finding (propose/verify/adjudicate not all ran), so the
25	//                 clean verdict is true by construction rather than because a real check ran.
26	
27	const { verifyPayload } = require('../../reference-set/verify.js');
28	
29	// knownBreachStatus(report, label, breachLaneComplete) -> 'reproduced' | 'missed' | 'skipped'.
30	function knownBreachStatus(report, label, breachLaneComplete) {
31	  const reproduced = report.matches.some((m) => m.check === 'known_breach' && m.detail === label);
32	  if (reproduced) return 'reproduced';
33	  return breachLaneComplete ? 'missed' : 'skipped';
34	}
35	
36	// knownNonBreachStatus(report, label) -> 'contradiction' | 'clean'.
37	function knownNonBreachStatus(report, label) {
38	  const hit = report.contradictions.some((c) => c.check === 'known_non_breach' && c.detail.startsWith(label + ':'));
39	  return hit ? 'contradiction' : 'clean';
40	}
41	
42	// judgeKnownBreaches(exp, report, breachLaneComplete) -> [{id, framework, status}]
43	function judgeKnownBreaches(exp, report, breachLaneComplete) {
44	  const list = Array.isArray(exp && exp.known_breaches) ? exp.known_breaches : [];
45	  return list.map((kb) => ({
46	    id: kb.id || null,
47	    framework: kb.framework || null,
48	    status: knownBreachStatus(report, kb.id || kb.framework, breachLaneComplete),
49	  }));
50	}
51	
52	// judgeKnownNonBreaches(exp, report, breachLaneComplete) -> [{id, framework, status, trivial}]
53	function judgeKnownNonBreaches(exp, report, breachLaneComplete) {
54	  const list = Array.isArray(exp && exp.known_non_breaches) ? exp.known_non_breaches : [];
55	  return list.map((knb) => {
56	    const label = knb.id || knb.framework;
57	    const status = knownNonBreachStatus(report, label);
58	    return { id: knb.id || null, framework: knb.framework || null, status, trivial: status === 'clean' && !breachLaneComplete };
59	  });
60	}
61	
62	/**
63	 * judgeFirm(firm, pipelineResult) -> {
64	 *   domain, role, report, knownBreaches:[{id,framework,status}],
65	 *   knownNonBreaches:[{id,framework,status,trivial}], contradiction:boolean
66	 * }
67	 *
68	 * `firm` is a reference-set.json entry shape ({domain, role, expected:{...}}) - or a synthetic
69	 * fixture's equivalent (eval/e2e/lib/synthetic-fixtures.js). `contradiction` is true when
70	 * verifyPayload found ANY contradiction at all (identity/sector/jurisdiction/framework included, not
71	 * only known_non_breach), matching the P3 exit bar's "zero false accusations" reading literally.
72	 */
73	function judgeFirm(firm, pipelineResult) {
74	  const report = verifyPayload(pipelineResult.payload, firm);
75	  const breachLaneComplete = pipelineResult.breachLaneComplete;
76	  return {
77	    domain: firm.domain,
78	    role: firm.role || null,
79	    report,
80	    knownBreaches: judgeKnownBreaches(firm.expected, report, breachLaneComplete),
81	    knownNonBreaches: judgeKnownNonBreaches(firm.expected, report, breachLaneComplete),
82	    contradiction: !report.ok,
83	  };
84	}
85	
86	module.exports = {
87	  judgeFirm,
88	  judgeKnownBreaches,
89	  judgeKnownNonBreaches,
90	  knownBreachStatus,
91	  knownNonBreachStatus,
92	};
