2	// evidence/browser/deadline.js - the ONE hard deadline primitive for the browser lane
3	// (Constitution Rule 9 / caution.md C-040).
4	//
5	// WHY THIS FILE EXISTS: a stuck Chromium once held a mint hostage for 752 seconds because the
6	// browser's own internal goto timeout did not bound launch + networkidle. The lesson: a slow
7	// external dependency must DEGRADE the mint, never HANG it. Every browser step in observe.js is
8	// routed through this primitive, so no code path can await a promise that may never settle without
9	// a wall-clock ceiling on it. The primitive itself uses a real timer (setTimeout) that is always
10	// cleared on the winning path, so it leaves nothing pending in the event loop.
11	//
12	// This is a CAP, never a floor (Rule 8): it races an existing promise against a ceiling and takes
13	// whichever settles first. It never delays a fast promise and never imposes a minimum wait.
14	
15	// raceWithDeadline(promise, ms, now) -> Promise<{ timedOut, value?, elapsed }>.
16	//   - resolves { timedOut:false, value, elapsed } if `promise` settles (fulfils) within `ms`;
17	//   - resolves { timedOut:true, elapsed } if `ms` elapses first (the original promise is abandoned
18	//     in the background - the caller is responsible for force-closing whatever it holds);
19	//   - if `promise` REJECTS before the deadline, this rejects with that reason (the caller's
20	//     try/catch records it as a typed failure, Rule 4).
21	// `now` is an injected clock (default Date.now) so elapsed timing is testable without real waits.
22	function raceWithDeadline(promise, ms, now) {
23	  const clock = typeof now === 'function' ? now : Date.now;
24	  const start = clock();
25	  let timer = null;
26	  const timeout = new Promise((resolve) => {
27	    timer = setTimeout(() => resolve({ timedOut: true, elapsed: clock() - start }), ms);
28	    if (timer && typeof timer.unref === 'function') timer.unref();
29	  });
30	  const work = Promise.resolve(promise).then((value) => ({ timedOut: false, value, elapsed: clock() - start }));
31	  return Promise.race([work, timeout]).finally(() => {
32	    if (timer) clearTimeout(timer);
33	  });
34	}
35	
36	// runWithDeadline(factory, ms, now) -> the same contract, but takes a promise FACTORY so the timed
37	// work is only started here. Convenience for call sites that build the promise inline.
38	function runWithDeadline(factory, ms, now) {
39	  let started;
40	  try {
41	    started = factory();
42	  } catch (e) {
43	    // FAIL-OPEN: a synchronous factory failure is a real error, not a timeout; it is re-raised as a
44	    // rejected promise so the caller's catch records it (Rule 4). Never silently swallowed.
45	    return Promise.reject(e);
46	  }
47	  return raceWithDeadline(started, ms, now);
48	}
49	
50	module.exports = { raceWithDeadline, runWithDeadline };
